import{_ as e,o as a,c as s,Q as o}from"./chunks/framework.e713b733.js";const m=JSON.parse('{"title":"Examples","description":"","frontmatter":{"sidebar":"auto"},"headers":[],"relativePath":"examples/index.md","filePath":"examples/index.md"}'),t={name:"examples/index.md"},n=o(`<h1 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h1><p>Examples are not intended to work out-of-the-box because they rely on data sources that might not be available or relevant for you. However they can be easily adapted to a working use case.</p><p>You can run a sample from the <em>examples</em> directory of the module like this:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#79B8FF;">cd</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">examples</span></span>
<span class="line"><span style="color:#6A737D;"># If local installation</span></span>
<span class="line"><span style="color:#B392F0;">node</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">..</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">./dem2csv/jobfile.js</span></span>
<span class="line"><span style="color:#6A737D;"># If global/executable installation</span></span>
<span class="line"><span style="color:#B392F0;">krawler</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">./dem2csv/jobfile.js</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#005CC5;">cd</span><span style="color:#24292E;"> </span><span style="color:#032F62;">examples</span></span>
<span class="line"><span style="color:#6A737D;"># If local installation</span></span>
<span class="line"><span style="color:#6F42C1;">node</span><span style="color:#24292E;"> </span><span style="color:#032F62;">..</span><span style="color:#24292E;"> </span><span style="color:#032F62;">./dem2csv/jobfile.js</span></span>
<span class="line"><span style="color:#6A737D;"># If global/executable installation</span></span>
<span class="line"><span style="color:#6F42C1;">krawler</span><span style="color:#24292E;"> </span><span style="color:#032F62;">./dem2csv/jobfile.js</span></span></code></pre></div><p>Intermediate and product outputs will be generated in the <em>ouput</em> folder. The main available samples are detailed below.</p><h2 id="ads-b" tabindex="-1">ADS-B <a class="header-anchor" href="#ads-b" aria-label="Permalink to &quot;ADS-B&quot;">​</a></h2><p>Grab <a href="https://en.wikipedia.org/wiki/Automatic_dependent_surveillance_%E2%80%93_broadcast" target="_blank" rel="noreferrer">ADS-B</a> data from two different providers using REST Web Services, convert it to a standardised JSON format, transform it to GeoJson and push it into AWS S3 and the local file system. To avoid &quot;holes&quot; the data from both providers are merged into a single file based on their unique identifier (a.k.a. <a href="https://en.wikipedia.org/wiki/Aviation_transponder_interrogation_modes#ICAO_24-bit_address" target="_blank" rel="noreferrer">ICAO</a>). Once the file has been produced simply drag&#39;n&#39;drop them at <a href="http://geojson.io" target="_blank" rel="noreferrer">geojson.io</a> to see the live position of the Air Maroc fleet !</p><p><img src="https://cdn.rawgit.com/kalisio/krawler/c4c7c00e3bd97390d6a9dd91c063d526f9c262e3/images/ADS-B.png" alt="ADS-B"></p><p>The <a href="./../reference/hooks.html">hooks</a> used are the following:</p><p><img src="https://cdn.rawgit.com/kalisio/krawler/fd6d4f356fb61824b6cd57d544040dc99d6c3a79/examples/adsb/Hooks%20Diagram.svg" alt="Hooks ADS-B"></p><p>Most parameters can be directly edited in the jobfile. However, for security concerns, some secrets are not hard-written in the jobfile, as a consequence you must define the following environment variables to make this sample work:</p><ul><li><strong>S3_ACCESS_KEY</strong> : AWS S3 Access Key ID</li><li><strong>S3_SECRET_ACCESS_KEY</strong> : AWS S3 Secret Access Key</li><li><strong>S3_BUCKET</strong> : the name of the S3 bucket to write the GeoJson file to</li></ul><p>The web services used according to the providers are the following:</p><ul><li><a href="https://www.adsbexchange.com/data/" target="_blank" rel="noreferrer">ADS-B Exchange</a></li><li><a href="https://opensky-network.org/apidoc/rest.html" target="_blank" rel="noreferrer">OpenSky Network</a></li></ul><p>This sample demonstrates the flexibility of the krawler by using:</p><ul><li>different output <a href="./../reference/services.html#stores">stores</a> and an intermediate <a href="./../reference/services.html#stores">in-memory store</a> to avoid writing temporary files,</li><li>a <a href="./../reference/hooks.html#common-options">match filter</a> to apply a given hook to a subset of the tasks (e.g. perform a JSON transformation adapted to the output of each provider)</li><li>a <a href="./../reference/hooks.html#transformjson-options">JSON transformation</a> to generate an unified format and filter data</li><li>the <a href="./../reference/known-issues.html#use-the-same-hook-multiple-times">same hook multiple times</a> (e.g. <code>writeJson</code>) with different options (e.g. to write to different output stores)</li><li>the same hook at the task or job level to manage unitary as well as merged data</li></ul><h2 id="vigicrues" tabindex="-1">Vigicrues <a class="header-anchor" href="#vigicrues" aria-label="Permalink to &quot;Vigicrues&quot;">​</a></h2><p>Grab data from the French flood warning system <a href="https://www.vigicrues.gouv.fr/" target="_blank" rel="noreferrer">Vigicrues</a> as GeoJson using REST Web Services, reproject it, style it according to alert level and push it into AWS S3 and the local file system. Once the file has been produced simply drag&#39;n&#39;drop it at <a href="http://geojson.io" target="_blank" rel="noreferrer">geojson.io</a> to see the live flood warnings !</p><p><img src="https://cdn.rawgit.com/kalisio/krawler/3632a68a7daa1bfd7df04bccc2a3c7817542e1f5/images/Vigicrue.png" alt="Vigicrues"></p><p>This sample is pretty similar to the ADS-B one plus:</p><ul><li>a <a href="./../reference/hooks.html#reprojectgeojson-options">reprojection</a> to transform data from the Lambert 93 projection system to the WGS 84 projection system</li><li>a <a href="./../reference/hooks.html#transformjson-options">JSON transformation</a> with value mapping to generate styling information</li></ul><h2 id="csv2db" tabindex="-1">csv2db <a class="header-anchor" href="#csv2db" aria-label="Permalink to &quot;csv2db&quot;">​</a></h2><p>Grab a CSV file from AWS S3, convert it to GeoJson and push it into a PostGIS database table or MongoDB database collection (it will be dropped if it already exists). The <a href="./../reference/hooks.html">hooks</a> used are the following for PG (MongoDB is similar):</p><p><img src="https://cdn.rawgit.com/kalisio/krawler/c85a9a96f08e090ff8b60b9df4adfa108f70bd7a/examples/csv2pg/Hooks%20Diagram.svg" alt="Hooks Blocks"></p><p>Some parameters like the input file name of the PostGIS host can be directly edited in the jobfile. However, for security concerns, some secrets are not hard-written in the jobfile, as a consequence you must define the following environment variables to make this sample work:</p><ul><li><strong>S3_ACCESS_KEY</strong> : AWS S3 Access Key ID</li><li><strong>S3_SECRET_ACCESS_KEY</strong> : AWS S3 Secret Access Key</li><li><strong>S3_BUCKET</strong> : the name of the S3 bucket to read the CSV file from</li><li><strong>PG_USER</strong> : the name of the PostgreSQL user to be used to connect</li><li><strong>PG_PASSWORD</strong> : the password of the PostgreSQL user to be used to connect</li></ul><h2 id="dem2csv" tabindex="-1">dem2csv <a class="header-anchor" href="#dem2csv" aria-label="Permalink to &quot;dem2csv&quot;">​</a></h2><p>Extract Digital Elevation Model <a href="https://en.wikipedia.org/wiki/Digital_elevation_model" target="_blank" rel="noreferrer">DEM</a> data from a WCS server and produces a CSV file. The output consists in a geographic grid of a given <em>width</em> (in meter) and <em>resolution</em> (in meter), centered around a location defined by [<em>longitude</em>, <em>latitude</em>] (in WGS84 degrees). Each row of the CSV contains the bounding box of a cell and the corresponding elevation value.</p><p>This sample is detailed in this <a href="https://blog.feathersjs.com/a-minimalist-etl-using-feathersjs-part-2-6aa89bd73d66" target="_blank" rel="noreferrer">article</a>.</p><blockquote><p>The original purpose was to ease ingestion of this data in a Hadoop system to perform some analysis</p></blockquote><p>The sample folder contains a job configuration stored in <a href="https://github.com/kalisio/krawler/blob/master/examples/dem2csv/jobfile.js" target="_blank" rel="noreferrer"><code>jobfile.js</code></a> to perform the process around a given location, which includes the hooks configuration in <a href="https://github.com/kalisio/krawler/blob/master/examples/dem2csv/hooks-blocks.js" target="_blank" rel="noreferrer"><code>hooks-blocks.js</code></a>.</p><p>The process can handle large datasets because the grid is split in a matrix of NxN blocks of <em>blockResolution</em> (in meter) to perform the data download and the merging of all block data relies on streams. The <a href="./../reference/hooks.html">hooks</a> used are the following:</p><p><img src="https://cdn.rawgit.com/kalisio/krawler/b46277bd9ef6b866e1a4d634766882345b9fd198/examples/dem2csv/Hooks%20Diagram%20Blocks.svg" alt="Hooks Blocks"></p><p>Here is what look like the (intermediate) outputs generated: grid blocks in <a href="https://github.com/kalisio/krawler/raw/master/test/data/RJTT-30-18000-2-1.csv" target="_blank" rel="noreferrer">CSV</a> and images</p><p><img src="https://github.com/kalisio/krawler/raw/master/examples/dem2csv/dem2csv-blocks.png" alt="Grid Blocks"></p><p>For illustration purpose we kept the original <a href="https://github.com/kalisio/krawler/blob/master/examples/dem2csv/hooks.js" target="_blank" rel="noreferrer">&quot;naïve&quot; implementation</a> that performed data download of each grid cell independently. However, processing time was too long on high resolution grids, the <a href="./../reference/hooks.html">hooks</a> used were the following:</p><p><img src="https://cdn.rawgit.com/kalisio/krawler/b46277bd9ef6b866e1a4d634766882345b9fd198/examples/dem2csv/Hooks%20Diagram.svg" alt="Hooks"></p><h2 id="docker" tabindex="-1">Docker <a class="header-anchor" href="#docker" aria-label="Permalink to &quot;Docker&quot;">​</a></h2><p>Provide web services with underlying pipeline functions managed using containers. This ensure you don&#39;t have to pollute your own operating system by installing anything except <a href="https://www.docker.com/" target="_blank" rel="noreferrer">Docker</a> and allow to make the processing scale on-demand, e.g. with an underlying <a href="https://docs.docker.com/engine/swarm/" target="_blank" rel="noreferrer">swarm cluster</a>.</p><h3 id="image-conversion-service" tabindex="-1">Image conversion service <a class="header-anchor" href="#image-conversion-service" aria-label="Permalink to &quot;Image conversion service&quot;">​</a></h3><p>Convert an image file from PNG to JPG using <a href="http://imagemagick.org" target="_blank" rel="noreferrer">ImageMagick</a> running in a temporary dedicated container.</p><blockquote><p>Before using this sample you will need to download the Image Magick image: <code>docker pull v4tech/imagemagick</code>.</p></blockquote><p>Launch the krawler as a web API with the job <code>krawler jobfile-convert.js --api</code> then POST the following request to <code>http://localhost:3030/api/jobs</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#E1E4E8;">	</span><span style="color:#79B8FF;">&quot;tasks&quot;</span><span style="color:#E1E4E8;">: [{ </span><span style="color:#79B8FF;">&quot;id&quot;</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;krawler-icon&quot;</span><span style="color:#E1E4E8;"> }]</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292E;">{</span></span>
<span class="line"><span style="color:#24292E;">	</span><span style="color:#005CC5;">&quot;tasks&quot;</span><span style="color:#24292E;">: [{ </span><span style="color:#005CC5;">&quot;id&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;krawler-icon&quot;</span><span style="color:#24292E;"> }]</span></span>
<span class="line"><span style="color:#24292E;">}</span></span></code></pre></div><p>You should see a <em>krawler-icon.jpg</em> file in the output folder once the job has been executed.</p><h3 id="map-print-service" tabindex="-1">Map print service <a class="header-anchor" href="#map-print-service" aria-label="Permalink to &quot;Map print service&quot;">​</a></h3><p>Take a screenshot of a map using <a href="https://github.com/DevExpress/testcafe" target="_blank" rel="noreferrer">TestCafé</a> running a <a href="https://leafletjs.com/" target="_blank" rel="noreferrer">Leaflet-based</a> <a href="http://kargo-www.s3-website.eu-central-1.amazonaws.com/" target="_blank" rel="noreferrer">web mapping client</a> in a temporary dedicated container and output the resulting image on S3.</p><p>This sample is detailed in this <a href="https://hackernoon.com/how-to-build-a-map-print-service-in-minutes-c5a24b1f0f41" target="_blank" rel="noreferrer">article</a>.</p><blockquote><p>Before using this sample you will need to build the required image from the sample directory: <code>docker build -t kalisio/leaflet-print .</code>.</p></blockquote><p>Launch the krawler as a web API with the job <code>krawler jobfile-print.js --api</code> then POST the following request containing the GeoJson data and print parameters to <code>http://localhost:3030/api/jobs</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#E1E4E8;">	</span><span style="color:#79B8FF;">&quot;tasks&quot;</span><span style="color:#E1E4E8;">: [{</span></span>
<span class="line"><span style="color:#E1E4E8;">		</span><span style="color:#79B8FF;">&quot;format&quot;</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;A4 Landscape&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">		</span><span style="color:#79B8FF;">&quot;baseLayer&quot;</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;PlanetSat&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">		</span><span style="color:#79B8FF;">&quot;data&quot;</span><span style="color:#E1E4E8;">: {</span></span>
<span class="line"><span style="color:#E1E4E8;">    		</span><span style="color:#79B8FF;">&quot;type&quot;</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;Feature&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">			</span><span style="color:#79B8FF;">&quot;geometry&quot;</span><span style="color:#E1E4E8;">: {</span></span>
<span class="line"><span style="color:#E1E4E8;">				</span><span style="color:#79B8FF;">&quot;type&quot;</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;LineString&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">				</span><span style="color:#79B8FF;">&quot;coordinates&quot;</span><span style="color:#E1E4E8;">: [[</span><span style="color:#79B8FF;">102.0</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">0.0</span><span style="color:#E1E4E8;">],[</span><span style="color:#79B8FF;">103.0</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">1.0</span><span style="color:#E1E4E8;">],[</span><span style="color:#79B8FF;">104.0</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">0.0</span><span style="color:#E1E4E8;">],[</span><span style="color:#79B8FF;">105.0</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">1.0</span><span style="color:#E1E4E8;">]]</span></span>
<span class="line"><span style="color:#E1E4E8;">			}</span></span>
<span class="line"><span style="color:#E1E4E8;">    	}</span></span>
<span class="line"><span style="color:#E1E4E8;">    }]</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292E;">{</span></span>
<span class="line"><span style="color:#24292E;">	</span><span style="color:#005CC5;">&quot;tasks&quot;</span><span style="color:#24292E;">: [{</span></span>
<span class="line"><span style="color:#24292E;">		</span><span style="color:#005CC5;">&quot;format&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;A4 Landscape&quot;</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">		</span><span style="color:#005CC5;">&quot;baseLayer&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;PlanetSat&quot;</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">		</span><span style="color:#005CC5;">&quot;data&quot;</span><span style="color:#24292E;">: {</span></span>
<span class="line"><span style="color:#24292E;">    		</span><span style="color:#005CC5;">&quot;type&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;Feature&quot;</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">			</span><span style="color:#005CC5;">&quot;geometry&quot;</span><span style="color:#24292E;">: {</span></span>
<span class="line"><span style="color:#24292E;">				</span><span style="color:#005CC5;">&quot;type&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;LineString&quot;</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">				</span><span style="color:#005CC5;">&quot;coordinates&quot;</span><span style="color:#24292E;">: [[</span><span style="color:#005CC5;">102.0</span><span style="color:#24292E;">,</span><span style="color:#005CC5;">0.0</span><span style="color:#24292E;">],[</span><span style="color:#005CC5;">103.0</span><span style="color:#24292E;">,</span><span style="color:#005CC5;">1.0</span><span style="color:#24292E;">],[</span><span style="color:#005CC5;">104.0</span><span style="color:#24292E;">,</span><span style="color:#005CC5;">0.0</span><span style="color:#24292E;">],[</span><span style="color:#005CC5;">105.0</span><span style="color:#24292E;">,</span><span style="color:#005CC5;">1.0</span><span style="color:#24292E;">]]</span></span>
<span class="line"><span style="color:#24292E;">			}</span></span>
<span class="line"><span style="color:#24292E;">    	}</span></span>
<span class="line"><span style="color:#24292E;">    }]</span></span>
<span class="line"><span style="color:#24292E;">}</span></span></code></pre></div><p>Once the job has been executed the response contains the link to download the printed image on S3 for each task:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#E1E4E8;">[</span></span>
<span class="line"><span style="color:#E1E4E8;">    {</span></span>
<span class="line"><span style="color:#E1E4E8;">        </span><span style="color:#79B8FF;">&quot;id&quot;</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;bc185cb0-7983-11e8-883f-a333a7402f4a&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">        </span><span style="color:#FDAEB7;font-style:italic;">...</span></span>
<span class="line"><span style="color:#E1E4E8;">        </span><span style="color:#79B8FF;">&quot;link&quot;</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;https://s3.eu-central-1.amazonaws.com/krawler/bc185cb0-7983-11e8-883f-a333a7402f4a.png&quot;</span></span>
<span class="line"><span style="color:#E1E4E8;">    }</span></span>
<span class="line"><span style="color:#E1E4E8;">]</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292E;">[</span></span>
<span class="line"><span style="color:#24292E;">    {</span></span>
<span class="line"><span style="color:#24292E;">        </span><span style="color:#005CC5;">&quot;id&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;bc185cb0-7983-11e8-883f-a333a7402f4a&quot;</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">        </span><span style="color:#B31D28;font-style:italic;">...</span></span>
<span class="line"><span style="color:#24292E;">        </span><span style="color:#005CC5;">&quot;link&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;https://s3.eu-central-1.amazonaws.com/krawler/bc185cb0-7983-11e8-883f-a333a7402f4a.png&quot;</span></span>
<span class="line"><span style="color:#24292E;">    }</span></span>
<span class="line"><span style="color:#24292E;">]</span></span></code></pre></div><h3 id="seeder" tabindex="-1">Seeder <a class="header-anchor" href="#seeder" aria-label="Permalink to &quot;Seeder&quot;">​</a></h3><p>The seeder take advantage of <a href="https://kalisio.github.io/kargo/" target="_blank" rel="noreferrer">Kargo</a> to seed a dataset. It relies on the seeding capabilities of <a href="https://mapproxy.org/docs/nightly/seed.html" target="_blank" rel="noreferrer">MapProxy</a>. The global approach is to subdivide the job into multiple tasks and run <code>mapprroxy-seed</code> utility for each task. To subdivide the job, we use a spatial grid and each cell is used as a coverage entry to limit the extend of the corresponding task. All the tasks, i.e. <code>mapproxy-seed</code> share the same MapProxy configuration file and use a generated seed file.</p><p>We use the same image of MapProxy as the one used in Kargo, but for now we do not use the benefits of a Swarm infrastructure to deploy the task. Meanwhile, if you plan to seed a layer with a source exposed by TileserverGL, you can easily scale the number of instances of TileserverGL to fit the required charge.</p><h2 id="bd-topo" tabindex="-1">BD TOPO <a class="header-anchor" href="#bd-topo" aria-label="Permalink to &quot;BD TOPO&quot;">​</a></h2><blockquote><p>Note: this example job has been entirely generated using AI (Claude) to check if it would be easily possible</p></blockquote><p>Download vector features from the French national topographic database <a href="https://geoservices.ign.fr/bdtopo" target="_blank" rel="noreferrer">BD TOPO</a> published by <a href="https://www.ign.fr/" target="_blank" rel="noreferrer">IGN</a> on the <a href="https://geoplateforme.fr/" target="_blank" rel="noreferrer">Géoplateforme</a> WFS service. The area of interest is defined by one or more EPCI SIREN codes and/or commune INSEE codes, resolved to actual commune geometries via the <a href="https://geoservices.ign.fr/adminexpress" target="_blank" rel="noreferrer">Admin Express</a> layer of the same service. The resulting features are written as a single GeoJSON file in the output folder.</p><p>The job runs in two phases:</p><ol><li><strong>Area resolution</strong> — Admin Express is queried to fetch the commune geometries matching the provided SIREN / INSEE codes. Their boundaries are unioned into a single polygon (adaptively simplified to keep the WFS filter URL within server limits) and used as a spatial <code>INTERSECTS</code> filter.</li><li><strong>Paginated download</strong> — the total feature count is probed first; one WFS task per page is then generated so that all pages are downloaded in parallel before being merged into a single <code>FeatureCollection</code>.</li></ol><p>The target data type is configurable. Available types in the <code>BDTOPO_V3</code> namespace:</p><table><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>batiment</code></td><td>Buildings</td></tr><tr><td><code>erp</code></td><td>Public buildings (Établissements Recevant du Public)</td></tr><tr><td><code>troncon_de_route</code></td><td>Road segments</td></tr><tr><td><code>troncon_voie_ferree</code></td><td>Railway segments</td></tr><tr><td><code>cours_d_eau</code></td><td>Waterways / Rivers</td></tr><tr><td><code>plan_d_eau</code></td><td>Water bodies / Lakes</td></tr><tr><td><code>zone_de_vegetation</code></td><td>Vegetation areas</td></tr><tr><td><code>surface_hydrographique</code></td><td>Hydrographic surfaces</td></tr><tr><td><code>aerodrome</code></td><td>Airports / Aerodromes</td></tr></tbody></table><p>The following environment variables control the job:</p><ul><li><strong>BDTOPO_SIREN</strong> : comma-separated EPCI SIREN codes (e.g. <code>243100518,200096956</code>). Defaults to <code>200096956</code> (Agen).</li><li><strong>BDTOPO_INSEE</strong> : comma-separated commune INSEE codes (e.g. <code>31555,31069,47001</code>). Can be used instead of or combined with <code>BDTOPO_SIREN</code>.</li><li><strong>BDTOPO_DATA_TYPE</strong> : BD TOPO feature type to download (default: <code>erp</code>).</li><li><strong>BDTOPO_COUNT</strong> : number of features per WFS page (default: <code>1000</code>).</li></ul><p>This sample demonstrates:</p><ul><li>a <strong>two-step job</strong> where the first step (area resolution via Admin Express) drives task generation for the second step (BD TOPO download),</li><li><strong>dynamic task generation</strong> using a custom <code>generateTasks</code> hook that computes the number of pages at runtime and generates one task per page,</li><li><strong>adaptive geometry simplification</strong> using <a href="https://turfjs.org/" target="_blank" rel="noreferrer">@turf/turf</a> to union commune polygons and simplify the result to a URL-safe WKT length, with a convex hull fallback,</li><li><strong>paginated WFS download</strong> with <code>startIndex</code>-based pagination and in-memory merge of all <code>FeatureCollection</code> pages via a custom <code>mergeGeoJson</code> hook.</li></ul>`,67),r=[n];function l(p,i,c,d,h,u){return a(),s("div",null,r)}const f=e(t,[["render",l]]);export{m as __pageData,f as default};
